import { API, Auth, Storage } from "aws-amplify";
import { getApprovedProfileCount, checkIsTagFingerPrinted, getProfileCount, getUnapprovedProfileCount, getUserTagByCreator, listProfiles } from "../graphql/queries";
import { approveProfile, createProfile, unApproveProfile, updateProfile } from "../graphql/mutations";
import config, { adminflag } from "../../config";

 let apiKey = config.APPSYNC_WEBSITE_API_KEY 
 export const websiteApi  = {
  authMode: 'API_KEY',
  headers: {
    'x-api-key': apiKey
  }
}


export async function getProfileByAuthId(sub){
  return API.graphql({
    query: listProfiles,
    variables: {
      filter: {
        auth_id: { eq: sub },
      },
    },...websiteApi,
  });
}


export async function createProfileForUser(input){
  return API.graphql({
    query: createProfile,
    variables: {
      input: {
       ...input,
      },
    },...websiteApi,
  });
}

export async function updateProfileForUser({input, condition}){
  return API.graphql({
    query: updateProfile,
    variables: {  
      input,
      condition,
    },...websiteApi
  })
}


export async function GetAllProfiles(limit = 10){
  return API.graphql({
    query: listProfiles, 
    variables: { "limit": limit },
    ...websiteApi
  })
}

export async function approveUser(profileId){
  return API.graphql({
    query: approveProfile, 
    variables: {
      id: profileId,
    },...websiteApi
  });
}


export async function disApproveUser(profileId){
  return API.graphql({
    query: unApproveProfile, 
    variables: {
      id: profileId,
    },...websiteApi
  });
}




export async function AdminAuth(){
  
 try {
   const user = await Auth.currentAuthenticatedUser();
   return adminflag.includes(user.attributes.email);
 } catch (error) {
  console.log(error)
  return false;
 }
}


export async function storeOnBucket({file, type, currentUser}) {
  try {
    let extension = file.name.split(".")[1];
    let contentType = extension == "pdf"? `application/pdf` : `image/${extension}`;
    let picName = `${currentUser?.attributes?.sub}/${type}.${extension}`;
    let picture_url = await Storage.put(picName, file, {
      contentType,
    });
    return picture_url
  } catch (error) {
    throw error;
  }
}


export async function getFromBucket(url){
  return Storage.get(url, { validateObjectExistence: true});
}

export function GetProfileCount(){
  return API.graphql({ query: getProfileCount, ...websiteApi})
}

export function GetUserTagByCreator(idCreator){
  return API.graphql({ query: getUserTagByCreator, variables: { idCreator }, ...websiteApi})
}

export function IsTagFingerPrinted(id){
  return API.graphql({ query: checkIsTagFingerPrinted, variables: { id }, ...websiteApi})
}


export function GetApprovedProfileCount(){
  return API.graphql({ query: getApprovedProfileCount, ...websiteApi})
}


export function GetUnapprovedProfileCount(){
  return API.graphql({ query: getUnapprovedProfileCount, ...websiteApi})
}



